// --- Fuzzy Search Helper for Categories ---
const findExpenseCategoryFuzzy = (name: string, categories: Category[]): Category | null => {
    if (!name) return null;
    const normalizedName = name.trim().toLowerCase();

    // 1. Exact match (case-insensitive)
    const exactMatch = categories.find(c => c.name.toLowerCase() === normalizedName);
    if (exactMatch) return exactMatch;

    // 2. Partial match (e.g., "Ocio" is in "Ocio y Restaurantes")
    const partialMatch = categories.find(c => c.name.toLowerCase().includes(normalizedName));
    if (partialMatch) return partialMatch;

    return null;
};

// --- Currency Parsing Helper ---
const parseCurrency = (value: any): number => {
    if (typeof value === 'number') return value;
    if (typeof value !== 'string') return NaN;

    let numericString = value.replace(/[€$EURUSD\s]/gi, '');
    if (numericString.includes(',') && numericString.includes('.')) {
        numericString = numericString.replace(/\./g, '').replace(',', '.');
    } else if (numericString.includes(',')) {
        numericString = numericString.replace(',', '.');
    }
    const parsed = parseFloat(numericString);
    return isNaN(parsed) ? NaN : parsed;
};


