    const isCurrentMonth = getMonthYear(selectedDate) === getMonthYear(new Date());

    const changeMonth = (amount: number) => {
        const newDate = new Date(selectedDate.getFullYear(), selectedDate.getMonth() + amount, 15);
        setSelectedDate(newDate);
    };

    return (
        <div className="month-navigator">
            <button onClick={() => changeMonth(-1)} className="month-nav-btn" aria-label="Mes anterior">
                &lt;
            </button>
            <button onClick={() => setIsMonthPickerOpen(true)} className="month-display" aria-label="Seleccionar mes y año">
                {selectedDate.toLocaleString('es-ES', { month: 'long', year: 'numeric' })}
            </button>
