const BudgetOverview = ({ filteredExpenses, filteredIncomes, expenseCategories, onCategoryClick }: {
    filteredExpenses: Expense[],
    filteredIncomes: Income[],
    expenseCategories: Category[],
    onCategoryClick: (category: Category) => void;
}) => {
    const categoryDetails = useMemo(() => {
        const expenseTotals = filteredExpenses.reduce((acc, expense) => {
            acc[expense.category] = (acc[expense.category] || 0) + expense.amount;
            return acc;
        }, {} as Record<string, number>);

        const reimbursementTotals = filteredIncomes.reduce((acc, income) => {
            if (income.isReimbursement && income.category) {
                acc[income.category] = (acc[income.category] || 0) + income.amount;
            }
            return acc;
        }, {} as Record<string, number>);

        const allCategoryNames = new Set([...Object.keys(expenseTotals), ...Object.keys(reimbursementTotals)]);
        const details: Record<string, { spent: number; reimbursed: number; net: number }> = {};

        for (const catName of allCategoryNames) {
            const spent = expenseTotals[catName] || 0;
            const reimbursed = reimbursementTotals[catName] || 0;
            details[catName] = { spent, reimbursed, net: spent - reimbursed };
        }
        return details;
    }, [filteredExpenses, filteredIncomes]);

    const displayCategories = expenseCategories.filter(cat => cat.name !== 'Ahorro');

    return (
      <div className="budget-overview">
        {displayCategories.map(cat => {
          const catData = categoryDetails[cat.name] || { spent: 0, reimbursed: 0, net: 0 };
          const spentNet = catData.net;
          const progress = cat.amount > 0 ? (spentNet / cat.amount) * 100 : 0;
          return (
            <div key={cat.id} className="category-progress-clickable" onClick={() => onCategoryClick(cat)} role="button" tabIndex={0}>
              <div className="progress-label-container">
                  <label>{cat.icon} {cat.name}</label>
                  <span className="progress-percentage">{Math.round(progress)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className={`progress-bar-inner ${progress > 100 ? 'over-budget' : ''}`} 
                  style={{ width: `${Math.min(Math.max(progress, 0), 100)}%` }}
                  aria-valuenow={progress}
                ></div>
              </div>
              <div className="progress-amount-container">
                  <span className="spent-amount">{formatCurrency(spentNet)}</span>
                  <span> / {formatCurrency(cat.amount)}</span>
                  {catData.reimbursed > 0 && (
                    <small className="reimbursement-detail">
                        (Gastado: {formatCurrency(catData.spent)}, Reembolsado: {formatCurrency(catData.reimbursed)})
                    </small>
                  )}
              </div>
            </div>
          );
        })}
      </div>
    );
};

const ExpenseDonutChart = ({ filteredExpenses, expenseCategories }: { filteredExpenses: Expense[], expenseCategories: Category[] }) => {
    const chartData = useMemo(() => {
        const expenseTotals = filteredExpenses.reduce((acc, expense) => {
            acc[expense.category] = (acc[expense.category] || 0) + expense.amount;
            return acc;
        }, {} as Record<string, number>);

        const totalSpentInMonth = Object.values(expenseTotals).reduce((sum, amount) => sum + amount, 0);
        if (totalSpentInMonth === 0) return null;

        const chartCategories = expenseCategories.filter(cat => cat.name !== 'Ahorro');
        const labels = chartCategories.map(cat => `${cat.icon || '❓'} ${cat.name}`);
        const data = chartCategories.map(cat => expenseTotals[cat.name] || 0);
        const backgroundColor = chartCategories.map((c, i) => CHART_COLORS[i % CHART_COLORS.length]);

        return {
            labels,
            datasets: [{
                label: 'Gasto',
                data,
                backgroundColor,
                borderColor: 'var(--surface-color)',
                borderWidth: 2,
            }]
        };
    }, [filteredExpenses, expenseCategories]);

    const options = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: { display: false },
            tooltip: {
                callbacks: {
                    label: function(context: TooltipItem<'doughnut'>) {
                        const label = context.label || '';
                        const value = Number(context.raw) || 0;
                        if (value === 0) return null;
                        const total = (context.chart.data.datasets[0].data as number[]).reduce((s, v) => s + (Number(v) || 0), 0) || 1;
                        const percentage = ((value / total) * 100).toFixed(1);
                        return `${label}: ${formatCurrency(value)} (${percentage}%)`;
                    }
                }
            }
        },
        cutout: '60%',
    };

    return (
        <div className="chart-and-legend-wrapper">
            <div className="chart-container">
                {chartData ? <Doughnut data={chartData} options={options} /> : <p className="chart-placeholder">No hay datos de gastos para mostrar en este mes.</p>}
            </div>
            {chartData && (
                <div className="custom-legend">
                    {chartData.labels.map((label, index) => {
                        const value = chartData.datasets[0].data[index];
                        if (value === 0) return null;
                        return (
                            <div key={label} className="legend-item">
                                <span 
                                    className="legend-swatch" 
                                    style={{ backgroundColor: chartData.datasets[0].backgroundColor[index] }}
                                ></span>
                                <span className="legend-label">{label}</span>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

const IncomeExpenseLineChart = ({ incomes, expenses, goalContributions, selectedDate, timeRange, setTimeRange }: {
    incomes: Income[], expenses: Expense[], goalContributions: GoalContribution[], selectedDate: Date, timeRange: number, setTimeRange: (range: number) => void
}) => {
    const chartData = useMemo(() => {
        const labels: string[] = [];
        const incomeData: number[] = [];
        const expenseData: number[] = [];
        const savingsData: number[] = [];

        for (let i = timeRange - 1; i >= 0; i--) {
            const date = new Date(selectedDate.getFullYear(), selectedDate.getMonth() - i, 15);
            const monthYear = getMonthYear(date);
            labels.push(date.toLocaleString('es-ES', { month: 'short', year: '2-digit' }));

            const monthlyIncomes = incomes.filter(inc => inc.date && inc.date.startsWith(monthYear));
            const totalMonthlyRealIncome = monthlyIncomes
                .filter(inc => !inc.isReimbursement)
                .reduce((acc, inc) => acc + inc.amount, 0);
            incomeData.push(totalMonthlyRealIncome);

            const monthlyExpenses = expenses.filter(exp => exp.date && exp.date.startsWith(monthYear));
            const monthlyReimbursements = monthlyIncomes
                .filter(inc => inc.isReimbursement)
                .reduce((acc, inc) => acc + inc.amount, 0);
            const grossExpenses = monthlyExpenses.reduce((acc, exp) => acc + exp.amount, 0);
            const netExpenses = grossExpenses - monthlyReimbursements;
            expenseData.push(netExpenses < 0 ? 0 : netExpenses);

            const monthlyNetContributions = goalContributions
                .filter(c => c.date && c.date.startsWith(monthYear))
                .reduce((acc, c) => acc + c.amount, 0);
            savingsData.push(monthlyNetContributions > 0 ? monthlyNetContributions : 0);
        }

        return {
            labels,
            datasets: [
                {
                    label: 'Ingresos',
                    data: incomeData,
                    borderColor: '#69F0AE',
                    backgroundColor: 'rgba(105, 240, 174, 0.3)',
                    fill: true,
                    tension: 0.3,
                },
                {
                    label: 'Gastos Netos',
                    data: expenseData,
                    borderColor: '#FF5252',
                    backgroundColor: 'rgba(255, 82, 82, 0.3)',
                    fill: true,
                    tension: 0.3,
                },
                {
                    label: 'Ahorro',
                    data: savingsData,
                    borderColor: '#FF9F40',
                    backgroundColor: 'rgba(255, 159, 64, 0.3)',
                    fill: true,
                    tension: 0.3,
                }
            ]
        };
    }, [incomes, expenses, goalContributions, selectedDate, timeRange]);

    const options = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: { position: 'top' as const, labels: { color: 'white' } },
            tooltip: { mode: 'index' as const, intersect: false }
        },
        scales: {
            y: { ticks: { color: 'white' }, grid: { color: 'rgba(255, 255, 255, 0.2)' } },
            x: { ticks: { color: 'white' }, grid: { color: 'rgba(255, 255, 255, 0.2)' } }
        }
    };

    return (
        <div className="card">
            <div className="chart-card-header">
                <h2>Evolución Financiera</h2>
                <div className="time-range-selector">
                    {[3, 6, 12].map(range => (
                        <button
                            key={range}
                            className={`time-range-btn ${timeRange === range ? 'active' : ''}`}
                            onClick={() => setTimeRange(range)}
                        >
                            {range}M
                        </button>
                    ))}
                </div>
            </div>
            <div className="chart-container">
                <Line data={chartData} options={options} />
            </div>
        </div>
    );
};

