                                    </div>
                                    <div className="progress-amount-container">
                                        <span className="spent-amount" style={{color: 'var(--savings-color)'}}>{formatCurrency(goal.currentAmount)}</span>
                                        <span> / {formatCurrency(goal.targetAmount)}</span>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                    <div className="list-summary" style={{ marginTop: 'auto', paddingTop: '1rem', borderTop: '1px solid var(--border-color)', background: 'transparent' }}>
                        <span>Total Ahorrado</span>
                        <span className="amount" style={{color: 'var(--savings-color)'}}>{formatCurrency(totalSaved)}</span>
                    </div>
                </>
            ) : (
                <p className="chart-placeholder" style={{padding: '2rem 0'}}>No has creado ninguna meta de ahorro todavía.</p>
            )}
        </div>
    );
};


