    const combined = [
      ...filteredIncomes.map(i => ({
        id: i.id, description: i.description, amount: i.amount, createdAt: i.createdAt, date: i.date, category: i.category, isReimbursement: i.isReimbursement,
        type: 'ingreso' as const, collection: 'incomes' as const, accountId: i.accountId,
      })),
      ...filteredExpenses.map(e => ({
        id: e.id, description: e.description, amount: e.amount, createdAt: e.createdAt, date: e.date, category: e.category, isReimbursement: undefined,
        type: 'gasto' as const, collection: 'expenses' as const, accountId: e.accountId,
      })),
       ...filteredContributions.map(c => {
         const goal = savingsGoals.find(g => g.id === c.goalId);
         const isWithdrawal = c.amount < 0;
         return {
            id: c.id, description: isWithdrawal ? `Retirada de: ${goal?.name || 'meta eliminada'}` : `Aportación a: ${goal?.name || 'meta eliminada'}`,
            amount: c.amount, createdAt: c.createdAt, date: c.date, category: 'Metas de Ahorro', icon: goal?.icon || '🎯',
            isReimbursement: undefined, type: 'aportacion' as const, collection: 'goalContributions' as const, goalId: c.goalId
         }
       }),
       ...filteredTransfers.map(t => {
          const fromAccount = accounts.find(a => a.id === t.fromAccountId);
          const toAccount = accounts.find(a => a.id === t.toAccountId);
          return {
            id: t.id, description: t.description || `Transferencia de ${fromAccount?.name || '?'} a ${toAccount?.name || '?'}`,
            amount: t.amount, createdAt: t.createdAt, date: t.date, type: 'transferencia' as const, collection: 'transfers' as const, from: fromAccount, to: toAccount,
          };
       })
    ];
    return combined.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime() || b.createdAt - a.createdAt);
  }, [filteredIncomes, filteredExpenses, filteredContributions, filteredTransfers, savingsGoals, accounts]);



