    if (!imageFile) return;

    setIsProcessing(true);
    setError(null);
    setPendingTransactions(null);

    const availableCategories = expenseCategories.filter(c => c.name !== 'Ahorro').map(c => c.name);

    const processPrompt = `
      Analiza la siguiente imagen de un ticket, factura o extracto bancario.
      Extrae todas las transacciones monetarias que encuentres.

      Instrucciones de clasificación:
      - Ingresos ('ingreso'): Son entradas de dinero.
      - Gastos ('gasto'): Son salidas de dinero.
      - Reembolsos ('reembolso'): Son devoluciones de dinero. Trátalos como un tipo especial de ingreso.
      - Ahorro en Hucha ('hucha'): Es dinero que se aparta para ahorrar, como 'ahorro en hucha'. Trátalo como una salida de dinero que no es un gasto.
      - Transferencias ('transferencia'): Son movimientos de dinero entre cuentas del propio usuario.

      Para cada transacción:
      1. Determina su tipo: 'ingreso', 'gasto', 'reembolso', 'hucha' o 'transferencia'.
      2. Extrae la descripción, el monto y la fecha. Formato YYYY-MM-DD. Fecha por defecto: ${formatDateForInput(new Date())}.
      3. Categoriza según la lista proporcionada: ${availableCategories.join(', ')}.
      Devuelve los resultados en el formato JSON especificado.
    `;

    const transactionSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING, enum: ['ingreso', 'gasto', 'reembolso', 'hucha', 'transferencia'] },
          description: { type: Type.STRING },
          amount: { type: Type.NUMBER },
          date: { type: Type.STRING },
          category: { type: Type.STRING }
        },
        required: ['type', 'description', 'amount', 'date']
      }
    };

    try {
      const imagePart = { inlineData: { data: imageFile.b64, mimeType: imageFile.mimeType } };
      const textPart = { text: processPrompt };
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [imagePart, textPart] },
        config: { responseMimeType: "application/json", responseSchema: transactionSchema }
      });
      const jsonResponse = JSON.parse(response.text);
      setPendingTransactions(jsonResponse);
        const initialAccountAssignments: Record<number, string> = {};
        const mainBankAccount = accounts.find(acc => acc.name === 'Banco Principal');
        const defaultAccountId = mainBankAccount?.id || accounts[0]?.id || '';
        if (defaultAccountId) {
            jsonResponse.forEach((tx: any, index: number) => { initialAccountAssignments[index] = defaultAccountId; });
        }
        setPendingTxAccount(initialAccountAssignments);
      setCategoryAssignments({});
      setShowManualAdd(false);
    } catch(err) {
      console.error(err);
      setError("Hubo un error al procesar el documento.");
    } finally { setIsProcessing(false); }
  }, [imageFile, expenseCategories, isOnline, accounts]);

