  const handleConfirmTransactions = async () => {
    if (!pendingTransactions) return;
    if (!allPendingCategorized) { setError("Por favor, completa todas las asignaciones."); return; }
    setError(null);
    const simpleBatch = db.batch();
    const paybackOperations: any[] = [];
    const timestamp = Date.now();
    const mainBankAccount = accounts.find(acc => acc.name === 'Banco Principal');
    const defaultAccountId = mainBankAccount?.id || accounts[0]?.id || '';
    let huchaGoalId = savingsGoals.find(g => g.name.toLowerCase() === 'hucha')?.id;

    if (pendingTransactions.some(tx => tx.type === 'hucha') && !huchaGoalId) {
        try {
            const docRef = await db.collection("savingsGoals").add({ name: "Hucha", targetAmount: 1000, icon: '🐷', currentAmount: 0, createdAt: Date.now() });
            huchaGoalId = docRef.id;
        } catch (err) { console.error(err); }
    }

    for (const [index, tx] of pendingTransactions.entries()) {
        const linkedReimbursementId = pendingTxReimbursementLink[index];
        const linkedGoalId = pendingTxGoalLink[index];
        const accountId = pendingTxAccount[index];
        const transferDetails = pendingTxTransferDetails[index];

        if ((tx.type === 'ingreso' || tx.type === 'reembolso') && linkedReimbursementId) {
            const linkedSE = sharedExpenses.find(se => se.id === linkedReimbursementId);
            const originalExpense = expenses.find(e => e.id === linkedSE?.originalExpenseId);
            if (linkedSE && originalExpense) {
                paybackOperations.push({ tx, sharedExpenseId: linkedReimbursementId, originalCategory: originalExpense.category, timestamp: timestamp + index });
            }
            continue;
        }

        if (tx.type === 'gasto' && linkedGoalId) {
            const goalRef = db.collection("savingsGoals").doc(linkedGoalId);
            const contributionRef = db.collection("goalContributions").doc();
            simpleBatch.update(goalRef, { currentAmount: firebase.firestore.FieldValue.increment(Number(tx.amount)) });
            simpleBatch.set(contributionRef, { goalId: linkedGoalId, amount: Number(tx.amount), date: tx.date || formatDateForInput(new Date()), createdAt: timestamp + index });
            continue;
        }

        const sharedDetails = pendingTxShared[index];
        if (tx.type === 'transferencia') {
            if (transferDetails?.from && transferDetails?.to) {
                simpleBatch.set(db.collection("transfers").doc(), { description: tx.description, amount: tx.amount, fromAccountId: transferDetails.from, toAccountId: transferDetails.to, date: tx.date || formatDateForInput(new Date()), createdAt: timestamp + index });
            }
        } else if (tx.type === 'ingreso' || tx.type === 'reembolso') {
            const finalCat = categoryAssignments[index] || tx.category;
            simpleBatch.set(db.collection("incomes").doc(), { description: tx.description, amount: tx.amount, date: tx.date || formatDateForInput(new Date()), isReimbursement: tx.type === 'reembolso' || (getCategoryByName(finalCat || '')?.type === 'expense'), createdAt: timestamp + index, accountId: accountId!, category: finalCat });
        } else if (tx.type === 'hucha' && huchaGoalId) {
            simpleBatch.update(db.collection("savingsGoals").doc(huchaGoalId), { currentAmount: firebase.firestore.FieldValue.increment(Number(tx.amount)) });
            simpleBatch.set(db.collection("goalContributions").doc(), { goalId: huchaGoalId, amount: Number(tx.amount), date: tx.date || formatDateForInput(new Date()), createdAt: timestamp + index });
        } else if (sharedDetails?.isShared && tx.type === 'gasto') {
            const myShare = parseFloat(sharedDetails.myShare || '0');
            const expenseRef = db.collection("expenses").doc();
            simpleBatch.set(expenseRef, { description: tx.description, amount: tx.amount, date: tx.date || formatDateForInput(new Date()), category: categoryAssignments[index] || tx.category!, createdAt: timestamp + index, accountId: accountId! });
            simpleBatch.set(db.collection("sharedExpenses").doc(), { originalExpenseId: expenseRef.id, description: tx.description, totalAmount: tx.amount, myShare, amountToReimburse: tx.amount - myShare, amountReimbursed: 0, status: 'open', notes: '', date: tx.date || formatDateForInput(new Date()), createdAt: timestamp + index });
        } else {
            simpleBatch.set(db.collection("expenses").doc(), { description: tx.description, amount: tx.amount, date: tx.date || formatDateForInput(new Date()), category: categoryAssignments[index] || tx.category!, createdAt: timestamp + index, accountId: accountId! });
        }
    }
    try { await simpleBatch.commit(); clearPendingState(); } catch (err) { setError("Error al guardar."); }
  };

