  const handleDeleteTransaction = async (id: string, type: string, amount: number, goalId?: string) => {
      setDeletingId(id);
      try {
          if (type === 'goalContributions' && goalId) {
              await db.runTransaction(async (t: any) => {
                  t.delete(db.collection(type).doc(id));
                  t.update(db.collection("savingsGoals").doc(goalId), { currentAmount: firebase.firestore.FieldValue.increment(-amount) });
              });
          } else if (type === 'expenses') {
              const batch = db.batch();
              const snap = await db.collection("sharedExpenses").where("originalExpenseId", "==", id).limit(1).get();
              if (!snap.empty) {
                  const seId = snap.docs[0].id;
                  const paybacks = await db.collection("incomes").where("sharedExpenseId", "==", seId).get();
                  paybacks.docs.forEach((doc: any) => batch.delete(doc.ref));
                  batch.delete(snap.docs[0].ref);
              }
              batch.delete(db.collection("expenses").doc(id));
              await batch.commit();
          } else if (type === 'incomes') {
              const inc = incomes.find(i => i.id === id);
              if (inc?.sharedExpenseId) {
                  await db.runTransaction(async (t: any) => {
                      const seRef = db.collection("sharedExpenses").doc(inc.sharedExpenseId);
                      const seDoc = await t.get(seRef);
                      if (seDoc.exists) {
                          const nTotal = seDoc.data().amountReimbursed - amount;
                          t.update(seRef, { amountReimbursed: nTotal, status: nTotal < seDoc.data().amountToReimburse ? 'open' : 'closed' });
                      }
                      t.delete(db.collection("incomes").doc(id));
                  });
              } else await db.collection("incomes").doc(id).delete();
