// New Data Model for Shared Expenses
interface SharedExpense {
  id: string;
  originalExpenseId: string; // Link to the original expense entry in the 'expenses' collection
  description: string;
  totalAmount: number; // The full amount of the original expense
  myShare: number; // The part the user is responsible for
  amountToReimburse: number; // totalAmount - myShare
