// --- Month Picker Component ---
const MonthPicker = ({ currentDate, onSelect, onClose }: { currentDate: Date, onSelect: (date: Date) => void, onClose: () => void }) => {
    const [displayYear, setDisplayYear] = useState(currentDate.getFullYear());
    const currentYear = new Date().getFullYear();
    const currentMonth = new Date().getMonth();

    const months = [
        "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
        "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
    ];

    const selectMonth = (monthIndex: number) => {
        onSelect(new Date(displayYear, monthIndex, 15));
    };

    return (
        <div className="month-picker-overlay" onClick={onClose}>
            <div className="month-picker" onClick={(e) => e.stopPropagation()}>
                <div className="month-picker-header">
                    <button onClick={() => setDisplayYear(y => y - 1)} className="month-picker-nav-btn">&lt;</button>
                    <span className="month-picker-year">{displayYear}</span>
                    <button onClick={() => setDisplayYear(y => y + 1)} className="month-picker-nav-btn" disabled={displayYear >= currentYear}>&gt;</button>
                </div>
                <div className="month-picker-grid">
                    {months.map((month, index) => {
                        const isSelected = index === currentDate.getMonth() && displayYear === currentDate.getFullYear();
                        const isDisabled = displayYear === currentYear && index > currentMonth;
                        return (
                            <button
                                key={month}
                                className={`month-picker-item ${isSelected ? 'selected' : ''}`}
                                onClick={() => selectMonth(index)}
                                disabled={isDisabled}
                            >
                                {month}
                            </button>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};


// --- Date Helper Functions ---
const formatCurrency = (amount: number) => new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(amount);

const formatDateForDisplay = (dateString: string) => {
    if (!dateString || !dateString.includes('-')) return 'N/A';
    const [year, month, day] = dateString.split('-');
    return `${day}/${month}/${year}`;
};

const getMonthYear = (date: Date) => {
    return date.toISOString().slice(0, 7); // YYYY-MM
};

const formatDateForInput = (date: Date) => {
    return date.toISOString().split('T')[0];
};

