  const totalBalanceAtStartOfMonth = useMemo(() => {
    const startOfMonth = new Date(selectedDate.getFullYear(), selectedDate.getMonth(), 1);
    const startOfMonthStr = formatDateForInput(startOfMonth);
    const balances = new Map<string, number>();
    accounts.forEach(acc => balances.set(acc.id, acc.initialBalance));
    const mainBankAccount = accounts.find(acc => acc.name === 'Banco Principal');
    const defaultAccountId = mainBankAccount?.id || (accounts.length > 0 ? accounts[0].id : 'default');
    const getAccountId = (tx: {accountId?: string}) => tx.accountId || defaultAccountId;

    incomes.forEach(inc => {
        if (inc.date < startOfMonthStr) {
            const accId = getAccountId(inc);
            balances.set(accId, (balances.get(accId) || 0) + Number(inc.amount));
        }
    });
    expenses.forEach(exp => {
        if (exp.date < startOfMonthStr) {
            const accId = getAccountId(exp);
            balances.set(accId, (balances.get(accId) || 0) - Number(exp.amount));
        }
    });
    transfers.forEach(t => {
        if (t.date < startOfMonthStr) {
            if (t.fromAccountId && balances.has(t.fromAccountId)) {
                balances.set(t.fromAccountId, (balances.get(t.fromAccountId) || 0) - Number(t.amount));
            }
            if (t.toAccountId && balances.has(t.toAccountId)) {
                balances.set(t.toAccountId, (balances.get(t.toAccountId) || 0) + Number(t.amount));
            }
        }
    });
    goalContributions.forEach(gc => {
        if (gc.date < startOfMonthStr && balances.has(defaultAccountId)) {
            balances.set(defaultAccountId, (balances.get(defaultAccountId) || 0) - Number(gc.amount));
        }
    });
    return Array.from(balances.values()).reduce((sum, bal) => sum + bal, 0);
  }, [selectedDate, accounts, incomes, expenses, transfers, goalContributions]);

  const accountBalances = useMemo(() => {
      const endOfMonthDate = new Date(selectedDate.getFullYear(), selectedDate.getMonth() + 1, 0);
      const endOfMonthStr = formatDateForInput(endOfMonthDate);
      const balances = new Map<string, number>();
      accounts.forEach(acc => balances.set(acc.id, acc.initialBalance));
      const mainBankAccount = accounts.find(acc => acc.name === 'Banco Principal');
      const defaultAccountId = mainBankAccount?.id || (accounts.length > 0 ? accounts[0].id : 'default');
      const getAccountId = (tx: {accountId?: string}) => tx.accountId || defaultAccountId;

      incomes.forEach(inc => {
          if (inc.date <= endOfMonthStr) {
              const accId = getAccountId(inc);
              balances.set(accId, (balances.get(accId) || 0) + Number(inc.amount));
          }
      });
      expenses.forEach(exp => {
          if (exp.date <= endOfMonthStr) {
              const accId = getAccountId(exp);
              balances.set(accId, (balances.get(accId) || 0) - Number(exp.amount));
          }
      });
      transfers.forEach(t => {
          if (t.date <= endOfMonthStr) {
              if (t.fromAccountId && balances.has(t.fromAccountId)) {
                  balances.set(t.fromAccountId, (balances.get(t.fromAccountId) || 0) - Number(t.amount));
              }
              if (t.toAccountId && balances.has(t.toAccountId)) {
                  balances.set(t.toAccountId, (balances.get(t.toAccountId) || 0) + Number(t.amount));
              }
          }
      });
      goalContributions.forEach(gc => {
          if (gc.date <= endOfMonthStr && balances.has(defaultAccountId)) {
              balances.set(defaultAccountId, (balances.get(defaultAccountId) || 0) - Number(gc.amount));
          }
      });
      return balances;
  }, [accounts, incomes, expenses, transfers, goalContributions, selectedDate]);

