    setPendingTransactions(prev => prev?.filter((_, i) => i !== indexToDelete) || null);
    const shiftKeys = (obj: Record<number, any>) => {
        const n: Record<number, any> = {};
        Object.keys(obj).forEach(kStr => {
            const k = parseInt(kStr, 10);
            if (k < indexToDelete) n[k] = obj[k]; else if (k > indexToDelete) n[k-1] = obj[k];
        });
        return n;
    };
    setCategoryAssignments(prev => shiftKeys(prev));
    setPendingTxShared(prev => shiftKeys(prev));
    setPendingTxReimbursementLink(prev => shiftKeys(prev));
    setPendingTxGoalLink(prev => shiftKeys(prev));
    setPendingTxAccount(prev => shiftKeys(prev));
