            const amount = parseCurrency(args.amount);
            if (isNaN(amount)) return { success: false, reason: "Monto inválido." };
            await db.collection("categories").add({ name: args.name, amount, type: args.type, icon: args.icon || '❓' });
            return { success: true };
        } catch (err) { return { success: false, reason: "Error." }; }
    };

    const executeAddGoalContribution = async (args: {goalName: string, amount: any, type: 'contribution' | 'withdrawal'}) => {
        try {
            const amount = parseCurrency(args.amount);
            if (isNaN(amount)) return { success: false, reason: "Monto inválido." };
            const goal = savingsGoals.find(g => g.name.toLowerCase().includes(args.goalName.toLowerCase()));
            if (!goal) return { success: false, reason: "Meta no encontrada." };
            const finalAmount = args.type === 'withdrawal' ? -Math.abs(amount) : Math.abs(amount);
            await db.runTransaction(async (t: any) => {
                const doc = await t.get(db.collection("savingsGoals").doc(goal.id));
                if (args.type === 'withdrawal' && amount > doc.data().currentAmount) throw new Error("Saldo insuficiente en meta.");
                t.update(db.collection("savingsGoals").doc(goal.id), { currentAmount: firebase.firestore.FieldValue.increment(finalAmount) });
                t.set(db.collection("goalContributions").doc(), { goalId: goal.id, amount: finalAmount, date: formatDateForInput(new Date()), createdAt: Date.now() });
            });
            return { success: true };
        } catch (err: any) { return { success: false, reason: err.message || "Error." }; }
    };

  // --- AI Chat Logic ---
  useEffect(() => { chatSessionRef.current = null; setChatHistory([]); setPendingToolCall(null); }, [selectedDate]);
  useEffect(() => { if (chatWindowRef.current) chatWindowRef.current.scrollTop = chatWindowRef.current.scrollHeight; }, [chatHistory, isChatLoading, pendingToolCall]);

  const handleSendChatMessage = useCallback(async (message?: string) => {
    const chatMsg = message || chatInput.trim();
    if (!chatMsg || !isOnline || isChatLoading) return;
    const userMsg: ChatMessage = { role: 'user', text: chatMsg, id: Date.now() };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');
    setIsChatLoading(true);

    const tools = [{
        functionDeclarations: [
          {
            name: "add_expense",
            description: "Añade un nuevo gasto.",
            parameters: {
              type: Type.OBJECT,
              properties: {
                description: { type: Type.STRING },
                amount: { type: Type.STRING },
                category: { type: Type.STRING },
                date: { type: Type.STRING },
                accountName: { type: Type.STRING, description: "Nombre de la cuenta de origen." }
              },
              required: ["description", "amount", "category"]
            }
          },
          {
            name: "add_income",
            description: "Añade un nuevo ingreso.",
            parameters: {
              type: Type.OBJECT,
              properties: {
                description: { type: Type.STRING },
                amount: { type: Type.STRING },
                category: { type: Type.STRING },
                date: { type: Type.STRING },
                accountName: { type: Type.STRING, description: "Nombre de la cuenta de destino." }
              },
              required: ["description", "amount"]
            }
          },
          {
            name: "update_budget",
            description: "Actualiza el presupuesto (monto) de una categoría.",
            parameters: {
                type: Type.OBJECT,
                properties: {
                    categoryName: { type: Type.STRING },
                    newAmount: { type: Type.STRING }
                },
                required: ["categoryName", "newAmount"]
            }
          },
          {
            name: "add_category",
            description: "Crea una nueva categoría de gasto o ingreso.",
            parameters: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING },
                    amount: { type: Type.STRING, description: "Presupuesto o meta inicial." },
                    type: { type: Type.STRING, enum: ["expense", "income"] },
                    icon: { type: Type.STRING }
                },
                required: ["name", "amount", "type"]
            }
          },
          {
            name: "add_goal_contribution",
            description: "Añade fondos o retira dinero de una meta de ahorro.",
            parameters: {
                type: Type.OBJECT,
                properties: {
                    goalName: { type: Type.STRING },
                    amount: { type: Type.STRING },
                    type: { type: Type.STRING, enum: ["contribution", "withdrawal"] }
                },
                required: ["goalName", "amount", "type"]
            }
          }
        ]
    }];

    try {
        if (!chatSessionRef.current) {
            chatSessionRef.current = ai.chats.create({
                model: 'gemini-3-flash-preview',
                tools,
                config: {
                    systemInstruction: `Eres FinancIA, asesor experto. Puedes añadir gastos, ingresos, categorías, aportaciones a metas y editar presupuestos. 
                    Cuentas disponibles: ${accounts.map(a => a.name).join(', ')}.
                    Metas de ahorro: ${savingsGoals.map(g => g.name).join(', ')}.
                    Categorías actuales: ${categories.map(c => `${c.name} (${c.type})`).join(', ')}.
                    Sé conciso y servicial.`
                }
            });
        }

        const financialContext = `Resumen ${selectedDate.toLocaleString('es-ES', { month: 'long', year: 'numeric' })}: Saldo: ${formatCurrency(totalInAccounts)}, Ingresos: ${formatCurrency(totalRealIncome)}, Gastos: ${formatCurrency(totalNetExpenses)}.`;
        const stream = await chatSessionRef.current!.sendMessageStream({ message: chatSessionRef.current!.history.length === 0 ? `Contexto: ${financialContext}\n\n${chatMsg}` : chatMsg });

        let resText = '';
        let toolCalls: ToolCallProposal[] = [];
        const mId = Date.now() + 1;
        setChatHistory(prev => [...prev, { role: 'model', text: '', id: mId }]);

        for await (const chunk of stream) {
            // Fix: Cast the chunk to GenerateContentResponse to fix 'unknown' type error when accessing properties like .text.
            const c = chunk as GenerateContentResponse;
            if (c.text) {
                resText += c.text;
                setChatHistory(prev => prev.map(m => m.id === mId ? { ...m, text: resText } : m));
            }
            if (c.functionCalls) {
                toolCalls.push(...c.functionCalls.filter(fc => !!fc.name).map(fc => ({ name: fc.name!, args: fc.args })));
            }
        }
        if (toolCalls.length > 0) {
            setChatHistory(prev => prev.filter(m => m.id !== mId));
            setPendingToolCall(toolCalls[0]);
        }
    } catch (err) {
        setChatHistory(prev => [...prev, { role: 'model', text: 'Error al procesar.', id: Date.now() + 1 }]);
    } finally { setIsChatLoading(false); }
  }, [chatInput, isOnline, isChatLoading, categories, expenseCategories, incomeCategories, savingsGoals, accounts, selectedDate, totalRealIncome, totalNetExpenses, totalInAccounts]);

  const handleToolCallResponse = useCallback(async (confirmed: boolean) => {
    if (!pendingToolCall) return;
    const tc = { ...pendingToolCall };
    setPendingToolCall(null);
    if (!confirmed) { setChatHistory(prev => [...prev, { role: 'model', id: Date.now(), text: "Operación cancelada." }]); return; }
    setIsChatLoading(true);
    try {
        let res;
        if (tc.name === 'add_expense') res = await executeAddExpense(tc.args);
        else if (tc.name === 'add_income') res = await executeAddIncome(tc.args);
        else if (tc.name === 'update_budget') res = await executeUpdateBudget(tc.args.categoryName, tc.args.newAmount);
        else if (tc.name === 'add_category') res = await executeAddCategory(tc.args);
        else if (tc.name === 'add_goal_contribution') res = await executeAddGoalContribution(tc.args);
        else res = { success: false, reason: "Función desconocida." };

        setChatHistory(prev => [...prev, { role: 'model', text: res.success ? "¡Hecho!" : `Error: ${res.reason}`, id: Date.now() }]);
    } catch (err) {
        setChatHistory(prev => [...prev, { role: 'model', text: 'Error inesperado.', id: Date.now() }]);
    } finally { setIsChatLoading(false); }
  }, [pendingToolCall, accounts, savingsGoals, categories]);

  const allPendingCategorized = useMemo(() => {
    if (!pendingTransactions) return true;
    return pendingTransactions.every((tx, index) => {
        if (tx.type === 'transferencia') {
            const d = pendingTxTransferDetails[index];
            return d && d.from && d.to && d.from !== d.to;
        }
        if (!pendingTxAccount[index]) return false;
        if (tx.type === 'gasto' && !pendingTxGoalLink[index]) return !!(tx.category || categoryAssignments[index]);
        return true; 
    });
  }, [pendingTransactions, categoryAssignments, pendingTxGoalLink, pendingTxAccount, pendingTxTransferDetails]);

  const isFirstTimeUser = useMemo(() => !isDataLoading && incomes.length === 0 && expenses.length === 0 && goalContributions.length === 0, [isDataLoading, incomes, expenses, goalContributions]);

  if (isDataLoading) return <div className="loader" style={{height: '100vh', flexDirection: 'column'}}><div className="spinner"></div><p style={{marginTop: '1rem'}}>Conectando...</p></div>;

  return (
    <>
      {pickerState.open && <EmojiPicker onSelectEmoji={handleEmojiSelect} onClose={() => setPickerState({ open: false, targetId: null })} />}
      {isMonthPickerOpen && <MonthPicker currentDate={selectedDate} onSelect={(date) => { setSelectedDate(date); setIsMonthPickerOpen(false); }} onClose={() => setIsMonthPickerOpen(false)} />}
      {isAccountModalOpen && editingAccount && (
        <div className="modal-overlay" onClick={() => setIsAccountModalOpen(false)}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                <h2>{editingAccount.id === 'new' ? 'Nueva Cuenta' : 'Editar Cuenta'}</h2>
                <div className="category-form" style={{gridTemplateColumns: 'auto 1fr', gap: '1rem'}}>
                    <button className="icon-picker-btn" onClick={() => setPickerState({ open: true, targetId: editingAccount.id === 'new' ? 'new-account' : `edit-account-${editingAccount.id}` })}>{editingAccount.icon}</button>
                    <input type="text" placeholder="Nombre" value={editingAccount.name} onChange={(e) => setEditingAccount(p => p ? {...p, name: e.target.value} : null)} />
                    <label style={{justifySelf: 'start'}}>Saldo Inicial (€)</label>
                    <input type="number" value={editingAccount.initialBalance || ''} onChange={(e) => setEditingAccount(p => p ? {...p, initialBalance: parseFloat(e.target.value) || 0} : null)} />
                </div>
                <div className="modal-controls"><button className="btn" onClick={handleSaveAccount}>Guardar</button><button className="btn btn-cancel" onClick={() => setIsAccountModalOpen(false)}>Cancelar</button></div>
            </div>
        </div>
      )}
      {isTransferModalOpen && (
        <div className="modal-overlay" onClick={() => setIsTransferModalOpen(false)}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                <h2>Transferencia</h2>
                <div className="form-stack">
                    <label>Desde</label><select value={transferData.from} onChange={(e) => setTransferData(p => ({...p, from: e.target.value}))}><option value="">Selecciona...</option>{accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.icon} {acc.name}</option>)}</select>
                    <label>Hacia</label><select value={transferData.to} onChange={(e) => setTransferData(p => ({...p, to: e.target.value}))}><option value="">Selecciona...</option>{accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.icon} {acc.name}</option>)}</select>
                    <label>Monto (€)</label><input type="number" value={transferData.amount} onChange={(e) => setTransferData(p => ({...p, amount: e.target.value}))} />
                    <label>Fecha</label><input type="date" value={transferData.date} onChange={(e) => setTransferData(p => ({...p, date: e.target.value}))} />
                </div>
                <div className="modal-controls"><button className="btn" onClick={handleCreateTransfer}>Confirmar</button><button className="btn btn-cancel" onClick={() => setIsTransferModalOpen(false)}>Cancelar</button></div>
            </div>
        </div>
      )}
      {budgetDetailCategory && (() => {
            const exps = filteredExpenses.filter(e => e.category === budgetDetailCategory.name);
            const reims = filteredIncomes.filter(i => i.isReimbursement && i.category === budgetDetailCategory.name);
            const all = [...exps.map(e => ({ ...e, type: 'expense' as const })), ...reims.map(i => ({ ...i, type: 'reimbursement' as const }))].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
            const totalS = exps.reduce((s, e) => s + e.amount, 0);
            const totalR = reims.reduce((s, i) => s + i.amount, 0);
            return (
                <div className="modal-overlay" onClick={() => setBudgetDetailCategory(null)}>
                    <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                        <h2>{budgetDetailCategory.icon} {budgetDetailCategory.name}</h2>
                        <ul className="transaction-list">{all.map(tx => (<li key={tx.id} className={`transaction-item ${tx.type}`}><span className="transaction-date">{formatDateForDisplay(tx.date)}</span><span className="description">{tx.description}</span><span className={`amount ${tx.type === 'expense' ? 'negative' : 'reimbursement'}`}>{tx.type === 'expense' ? '-' : '+'}{formatCurrency(tx.amount)}</span></li>))}</ul>
                        <div className="modal-controls"><button className="btn" onClick={() => setBudgetDetailCategory(null)}>Cerrar</button></div>
                    </div>
                </div>
            );
        })()}
      <header><h1>Gestor de Finanzas {!isOnline && <span className="offline-badge">Offline ☁️</span>}</h1><p>Control inteligente de tus ahorros y gastos.</p></header>
      <nav className="nav-dropdown-container" ref={navRef}><button className="nav-dropdown-toggle" onClick={() => setIsNavMenuOpen(!isNavMenuOpen)}><span>{activeTabName}</span><span className={`dropdown-arrow ${isNavMenuOpen ? 'open' : ''}`}></span></button>{isNavMenuOpen && (<div className="nav-dropdown-menu">{TABS.map(tab => (<button key={tab.id} className={`nav-dropdown-item ${activeTab === tab.id ? 'active' : ''}`} onClick={() => { setActiveTab(tab.id); setIsNavMenuOpen(false); }}>{tab.name}</button>))}</div>)}</nav>
      <MonthNavigator selectedDate={selectedDate} setSelectedDate={setSelectedDate} setIsMonthPickerOpen={setIsMonthPickerOpen} />
      <main>
        {activeTab === 'dashboard' && (<><AccountsQuickSummary accounts={accounts} accountBalances={accountBalances} totalInAccounts={totalInAccounts} /><div className="tab-content-grid"><FinancialSummary balanceAtStartOfMonth={totalBalanceAtStartOfMonth} totalRealIncome={totalRealIncome} totalNetExpenses={totalNetExpenses} totalGrossExpenses={totalExpenses} totalReimbursements={totalReimbursements} totalGoalContributions={totalMonthlyContributions} showSetInitialBalance={isFirstTimeUser} onSetInitialBalance={() => setIsInitialBalanceModalOpen(true)} /><div className="card"><h2>Metas</h2><GoalsQuickSummary savingsGoals={savingsGoals} /></div><div className="card"><h2>Presupuesto</h2><BudgetOverview filteredExpenses={filteredExpenses} filteredIncomes={filteredIncomes} expenseCategories={expenseCategories} onCategoryClick={(c) => setBudgetDetailCategory(c)} /></div></div><div className="charts-grid"><div className="card"><h2>Gastos</h2><ExpenseDonutChart filteredExpenses={filteredExpenses} expenseCategories={expenseCategories} /></div><IncomeExpenseLineChart incomes={incomes} expenses={expenses} goalContributions={goalContributions} selectedDate={selectedDate} timeRange={chartTimeRange} setTimeRange={setChartTimeRange} /></div></>)}
        {activeTab === 'cuentas' && (<div className="tab-content-grid single-column"><div className="card"><div className="goals-header"><h2>Cuentas</h2><div style={{display:'flex',gap:'1rem'}}><button className="btn btn-secondary" onClick={() => setIsTransferModalOpen(true)}>Transferencia</button><button className="btn" onClick={() => { setEditingAccount({ id: 'new', name: '', icon: '💳', initialBalance: 0, createdAt: 0 }); setIsAccountModalOpen(true); }}>Añadir</button></div></div></div><div className="account-card-grid">{accounts.map(a => (<div key={a.id} className="account-card"><div className="account-card-header"><h3>{a.icon} {a.name}</h3><div className="btn-edit-controls"><button onClick={() => { setEditingAccount(a); setIsAccountModalOpen(true); }} className="btn-action edit">Editar</button><button onClick={() => setConfirmingDeleteId(a.id)} className="btn-action delete">Eliminar</button></div></div><div className="account-card-body"><p className={`amount ${ (accountBalances.get(a.id) || 0) >= 0 ? 'positive' : 'negative'}`}>{formatCurrency(accountBalances.get(a.id) || 0)}</p></div></div>))}</div></div>)}
        {activeTab === 'advisor' && (
            <div className="tab-content-grid single-column">
                <div className="card chat-advisor-card">
                    <div className="chat-header"><h2>Asesor IA FinancIA</h2><p>Puedo añadir gastos, ingresos, metas y ajustar tus presupuestos.</p></div>
                    <div className="chat-window" ref={chatWindowRef}>
                        {chatHistory.length === 0 && (<div className="chat-placeholder-container"><p>¡Hola! ¿En qué puedo ayudarte hoy?</p><ul><li>"Añade un gasto de 12€ en Supermercado"</li><li>"Cambia mi presupuesto de Ocio a 200€"</li><li>"Crea una categoría de Viajes con 100€ de presupuesto"</li><li>"Añade 50€ a mi meta de Coche"</li></ul></div>)}
                        {chatHistory.map(m => (<div key={m.id} className={`chat-message ${m.role}`}><div className="chat-bubble" dangerouslySetInnerHTML={{ __html: m.text.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>').replace(/\n/g, '<br />') }}></div></div>))}
                        {isChatLoading && !pendingToolCall && (<div className="chat-message model"><div className="chat-bubble typing-indicator"><span></span><span></span><span></span></div></div>)}
                    </div>
                    <div className="chat-input-area">
                       {pendingToolCall && (
                            <div className="tool-call-card">
                                <h4>Acción sugerida:</h4>
                                <div className="tool-call-details">
                                    <p><strong>{pendingToolCall.name === 'add_expense' ? 'Añadir Gasto' : pendingToolCall.name === 'add_income' ? 'Añadir Ingreso' : pendingToolCall.name === 'update_budget' ? 'Editar Presupuesto' : pendingToolCall.name === 'add_category' ? 'Nueva Categoría' : 'Aportación a Meta'}</strong></p>
                                    <pre>{JSON.stringify(pendingToolCall.args, null, 2)}</pre>
                                </div>
                                <div className="tool-call-controls"><button className="btn" onClick={() => handleToolCallResponse(true)}>Confirmar</button><button className="btn btn-cancel" onClick={() => handleToolCallResponse(false)}>Cancelar</button></div>
                            </div>
                       )}
                        <textarea value={chatInput} onChange={e => setChatInput(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendChatMessage(); } }} placeholder="Escribe aquí..." rows={1} disabled={isChatLoading || !isOnline || !!pendingToolCall} />
                        <button onClick={() => handleSendChatMessage()} disabled={!chatInput.trim() || isChatLoading || !isOnline || !!pendingToolCall}>{isChatLoading ? <div className="spinner-small-white"></div> : 'Enviar'}</button>
                    </div>
                </div>
            </div>
        )}
        {activeTab === 'transactions' && (<div className="tab-content-grid single-column">{!pendingTransactions && (<div className="card"><h2>Importar Documento</h2><div className="uploader-container"><input type="file" id="f-up" className="file-input-hidden" onChange={handleFileChange} accept="image/*" /><label htmlFor="f-up" className="btn">Seleccionar Imagen</label>{imageFile && <span>{imageFile.name}</span>}</div>{imageFile && (<div className="image-preview-container"><img src={`data:${imageFile.mimeType};base64,${imageFile.b64}`} className="image-preview"/><button className="btn btn-secondary" onClick={handleProcessDocument} disabled={isProcessing}>{isProcessing ? 'Procesando...' : 'Analizar'}</button></div>)}</div>)}<div className="card"><h2>Historial</h2><ul className="transaction-list">{allTransactions.map(tx => (<li key={tx.id} className={`transaction-item ${tx.type}`}><span className="transaction-date">{formatDateForDisplay(tx.date)}</span><div><span className="description">{tx.description}</span><div className="tags-container">{tx.category && <span className="category">{tx.category}</span>}</div></div><span className={`amount ${tx.amount < 0 ? 'negative' : 'positive'}`}>{tx.amount < 0 ? '-' : '+'}{formatCurrency(Math.abs(tx.amount))}</span><div className="transaction-actions"><button onClick={() => setConfirmingDeleteId(tx.id)} className="btn-delete">&times;</button></div></li>))}</ul></div></div>)}
        {activeTab === 'categories' && (
           <div className="tab-content-grid single-column">
             <div className="card">
                <h2>Categorías</h2>
                <div className="category-management">
                    {['expense', 'income'].map(type => (
                        <div key={type}>
                            <h3 className="list-header">{type === 'expense' ? 'Gastos' : 'Ingresos'}</h3>
                            <ul className="category-list">{categories.filter(c => c.type === type).map(c => (<li key={c.id} className="category-item"><span>{c.icon} {c.name}</span><span className="amount">{formatCurrency(c.amount)}</span><div className="btn-edit-controls"><button onClick={() => handleEditCategory(c)} className="btn-action edit">Editar</button><button onClick={() => setConfirmingDeleteCategoryId(c.id)} className="btn-action delete">Eliminar</button></div></li>))}</ul>
                        </div>
                    ))}
                </div>
                <h3 className="list-header">Añadir Nueva</h3>
                <div className="category-form">
                    <select value={newCatType} onChange={e => setNewCatType(e.target.value as any)}><option value="expense">Gasto</option><option value="income">Ingreso</option></select>
                    <button className="icon-picker-btn" onClick={() => setPickerState({ open: true, targetId: 'new-category' })}>{newCatIcon}</button>
                    <input type="text" placeholder="Nombre" value={newCatName} onChange={e => setNewCatName(e.target.value)} />
                    <input type="number" placeholder="Monto" value={newCatAmount} onChange={e => setNewCatAmount(e.target.value)} />
                    <button className="btn" onClick={handleAddCategory}>+</button>
                </div>
             </div>
           </div>
        )}
      </main>
      {isInitialBalanceModalOpen && (<div className="modal-overlay"><div className="modal-content"><h2>Saldo Inicial</h2><input type="number" value={initialBalanceAmount} onChange={e => setInitialBalanceAmount(e.target.value)} /><div className="modal-controls"><button className="btn" onClick={handleSaveInitialBalance}>Guardar</button><button className="btn btn-cancel" onClick={() => setIsInitialBalanceModalOpen(false)}>Cancelar</button></div></div></div>)}
    </>
  );
};

